/* com.matjzing.mapper.FrontCategoryMapper.insertFrontCategory */
INSERT INTO CATEGORY (
	  NAME /**/
	, ICON_URL /**/
	, USE_YN /**/
	, REGISTER_SEQ /**/
	, REGISTER_IP /**/
	, REGISTRATION_DT /**/
	, UPDATER_SEQ /**/
	, UPDATER_IP /**/
	, UPDATE_DT /**/
) VALUES (
	  #{name}
	, #{iconUrl}
	, TRUE
	, #{registerSeq}
	, #{registerIp}
	, NOW(3)
	, #{updaterSeq}
	, #{updaterIp}
	, NOW(3)
)
